arguments.command:
cd /tmp
cat > sshtest.exp <<'EOF'
set timeout 60
spawn ssh -p 2222 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null root@localhost
expect {
    "password:" { send "password123\r" }
    timeout { puts "TIMEOUT waiting for pw"; exit 2 }
}
expect {
    -re {[#\$] $} { send "echo SSH_OK_MARKER; hostname; id\r" }
    timeout { puts "TIMEOUT after pw"; exit 3 }
}
expect "SSH_OK_MARKER"
expect -re {[#\$] $}
send "exit\r"
expect eof
EOF
expect sshtest.exp 2>&1 | tail -20

