arguments.command:
cd /tmp
cat > sshtest2.exp <<'EOF'
set timeout 60
spawn ssh -p 2222 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null root@localhost "echo GRADE_OK; whoami; cat /etc/alpine-release"
expect {
    "password:" { send "password123\r" }
    timeout { exit 2 }
}
expect eof
EOF
expect sshtest2.exp 2>&1 | tail -12
echo "=== qemu still running? ==="; ps aux | grep -c "[q]emu-system"

