arguments.command:
cd /tmp
cat > verify.exp <<'EOF'
set timeout 60
spawn ssh -p 2222 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null root@localhost "echo GRADE_OK=$(whoami)@$(hostname); cat /etc/alpine-release"
expect {
    "password:" { send "password123\r" }
    "assword:" { send "password123\r" }
    timeout { puts "FAIL: no password prompt"; exit 2 }
}
expect eof
EOF
expect verify.exp 2>&1 | grep -aE 'GRADE_OK|alpine|FAIL|[0-9]+\.[0-9]+\.[0-9]+'

